[Fact]
public void ShouldSupportPreciseAlignmentForUnicodeAndNumericData()
{
    var data = new List<User>
    {
        new User { Name = "Item 哈哈", Age = 100 },
        new User { Name = "Longer Item 🌲", Age = 1 }
    };

    var table = ConsoleTable
        .From(data)
        .Configure(o => o.NumberAlignment = Alignment.Right)
        .ToString();

    Assert.Equal(
        $"""
          ------------------------ 
          | Name           | Age |
          ------------------------ 
          | Item 哈哈      | 100 |
          ------------------------ 
          | Longer Item 🌲 |   1 |
          ------------------------ 

          Count: 2
         """, 
        table);
}
